class Solution:
    def minAnagramLength(self, s: str) -> int:
        from collections import Counter
        n = len(s)
        def check(d):
            base = Counter(s[:d])
            for i in range(d, n, d):
                if Counter(s[i:i+d]) != base:
                    return False
            return True
        for d in range(1, n+1):
            if n % d == 0 and check(d):
                return d
        return n

