var minAnagramLength = function(s) {
    const n = s.length;
    function check(d) {
        const base = {};
        for (let i = 0; i < d; i++) base[s[i]] = (base[s[i]] || 0) + 1;
        for (let start = d; start < n; start += d) {
            const cnt = {};
            for (let i = start; i < start + d; i++) cnt[s[i]] = (cnt[s[i]] || 0) + 1;
            const keys = new Set([...Object.keys(base), ...Object.keys(cnt)]);
            for (const k of keys) {
                if ((base[k] || 0) !== (cnt[k] || 0)) return false;
            }
        }
        return true;
    }
    for (let d = 1; d <= n; d++) {
        if (n % d === 0 && check(d)) return d;
    }
    return n;
};
